package cn.nobeta.dingdong.order.domain;
import java.math.BigDecimal;
import java.time.LocalDateTime;
public class MallOrder {
    private Long id; private String orderNo; private Long userId; private String receiverName; private String receiverPhone; private String receiverAddress; private BigDecimal totalAmount; private String status; private String carrier; private String trackingNo; private LocalDateTime shippedAt; private LocalDateTime createdAt;
    public Long getId(){return id;} public void setId(Long id){this.id=id;} public String getOrderNo(){return orderNo;} public void setOrderNo(String orderNo){this.orderNo=orderNo;} public Long getUserId(){return userId;} public void setUserId(Long userId){this.userId=userId;} public String getReceiverName(){return receiverName;} public void setReceiverName(String receiverName){this.receiverName=receiverName;} public String getReceiverPhone(){return receiverPhone;} public void setReceiverPhone(String receiverPhone){this.receiverPhone=receiverPhone;} public String getReceiverAddress(){return receiverAddress;} public void setReceiverAddress(String receiverAddress){this.receiverAddress=receiverAddress;} public BigDecimal getTotalAmount(){return totalAmount;} public void setTotalAmount(BigDecimal totalAmount){this.totalAmount=totalAmount;} public String getStatus(){return status;} public void setStatus(String status){this.status=status;} public String getCarrier(){return carrier;} public void setCarrier(String carrier){this.carrier=carrier;} public String getTrackingNo(){return trackingNo;} public void setTrackingNo(String trackingNo){this.trackingNo=trackingNo;} public LocalDateTime getShippedAt(){return shippedAt;} public void setShippedAt(LocalDateTime shippedAt){this.shippedAt=shippedAt;} public LocalDateTime getCreatedAt(){return createdAt;} public void setCreatedAt(LocalDateTime createdAt){this.createdAt=createdAt;}
}
